                IF sortDirection = FALSE THEN
                    comparisonResult := FALSE;
                    WHILE j > gap DO
                        IF sorted_arr[j - gap] > temp THEN
                            comparisonResult := TRUE;
                        ELSE
                            comparisonResult := FALSE;
                        END_IF;

                        IF comparisonResult = TRUE THEN
                            sorted_arr[j] := sorted_arr[j - gap];
                            j := j - gap;
                        ELSE
                            comparisonResult := FALSE;
                        END_IF;
                    END_WHILE;
                ELSE
                    comparisonResult := FALSE;
                    WHILE j > gap DO
                        IF sorted_arr[j - gap] < temp THEN
                            comparisonResult := TRUE;
                        ELSE
                            comparisonResult := FALSE;
                        END_IF;

                        IF comparisonResult = TRUE THEN
                            sorted_arr[j] := sorted_arr[j - gap];
                            j := j - gap;
                        ELSE
                            comparisonResult := FALSE;
                        END_IF;
                    END_WHILE;
                END_IF;

                sorted_arr[j] := temp;
            END_FOR;

            gap := gap / 2;
        END_WHILE;
    END_IF;
</patch>
